from dataclasses import dataclass, field
from typing import Optional


@dataclass
class TraceabilityRow:
    """One row in the traceability matrix."""
    behavior_spec_id: str      # e.g. "BEH-SPEC-02"
    behavior_spec_title: str   # human-readable: "Destination slot must resolve to IATA code"
    wireframe_node_id: str     # e.g. "NODE-A2" or "SCRIPT-OOS-01"
    handoff_artifact_id: str   # e.g. "HANDOFF-A2"
    engineering_ticket_id: str # e.g. "ENG-107"
    eval_test_case_ids: list[str]  # e.g. ["EVAL-A2-01", "EVAL-A2-02"]
    is_safety_relevant: bool = False  # True → Gate 2 reference required
    gate2_decision_id: Optional[str] = None  # required if is_safety_relevant

    def is_complete(self) -> bool:
        if not all([
            self.behavior_spec_id,
            self.wireframe_node_id,
            self.engineering_ticket_id,
            self.eval_test_case_ids,
        ]):
            return False
        if self.is_safety_relevant and not self.gate2_decision_id:
            return False
        return True

    def missing_fields(self) -> list[str]:
        missing = []
        if not self.behavior_spec_id:      missing.append("behavior_spec_id")
        if not self.wireframe_node_id:     missing.append("wireframe_node_id")
        if not self.engineering_ticket_id: missing.append("engineering_ticket_id")
        if not self.eval_test_case_ids:    missing.append("eval_test_case_ids")
        if self.is_safety_relevant and not self.gate2_decision_id:
            missing.append("gate2_decision_id")
        return missing


@dataclass
class TraceabilityMatrix:
    flow_id: str
    system_prompt_version: str
    rows: list[TraceabilityRow] = field(default_factory=list)

    def is_complete(self) -> bool:
        return all(r.is_complete() for r in self.rows)

    def incomplete_rows(self) -> list[TraceabilityRow]:
        return [r for r in self.rows if not r.is_complete()]

    def safety_rows_without_gate2(self) -> list[TraceabilityRow]:
        return [
            r for r in self.rows
            if r.is_safety_relevant and not r.gate2_decision_id
        ]

    def coverage_report(self) -> dict:
        return {
            "total_rows": len(self.rows),
            "complete": len(self.rows) - len(self.incomplete_rows()),
            "incomplete": [r.behavior_spec_id for r in self.incomplete_rows()],
            "safety_missing_gate2": [
                r.behavior_spec_id for r in self.safety_rows_without_gate2()
            ],
            "ready_for_engineering": self.is_complete(),
        }

from dataclasses import dataclass
from datetime import datetime


@dataclass
class ArtifactVersion:
    artifact_id: str
    version: str
    authored_by: str
    frozen_at: str            # ISO-8601; set on Gate 4 approval
    changelog: str            # what changed from prior version
    supersedes: str = ""      # prior version id, if any

    @property
    def is_frozen(self) -> bool:
        return bool(self.frozen_at)

    def can_be_modified(self) -> bool:
        return not self.is_frozen

    def freeze(self, timestamp: str) -> None:
        if self.is_frozen:
            raise ValueError(f"{self.artifact_id} is already frozen at {self.frozen_at}")
        self.frozen_at = timestamp


@dataclass
class HandoffPackage:
    package_id: str
    flow_id: str
    version: str
    artifacts: list[ArtifactVersion]
    traceability: TraceabilityMatrix
    gate4_approval_id: str = ""

    def freeze_all(self, timestamp: str) -> None:
        for artifact in self.artifacts:
            if not artifact.is_frozen:
                artifact.freeze(timestamp)

    def is_release_ready(self) -> bool:
        all_frozen = all(a.is_frozen for a in self.artifacts)
        trace_complete = self.traceability.is_complete()
        gate_approved = bool(self.gate4_approval_id)
        return all_frozen and trace_complete and gate_approved

from dataclasses import dataclass


@dataclass
class TraceabilityGapReport:
    matrix: TraceabilityMatrix
    authored_tickets: set[str]     # all ticket IDs created by engineering
    authored_eval_cases: set[str]  # all eval case IDs authored by QA

    def spec_elements_without_tickets(self) -> list[str]:
        return [
            r.behavior_spec_id
            for r in self.matrix.rows
            if r.engineering_ticket_id not in self.authored_tickets
        ]

    def eval_cases_without_nodes(self) -> list[str]:
        """Eval cases that do not appear in any traceability row."""
        traced_evals: set[str] = set()
        for row in self.matrix.rows:
            traced_evals.update(row.eval_test_case_ids)
        return [ec for ec in self.authored_eval_cases if ec not in traced_evals]

    def spec_elements_without_eval(self) -> list[str]:
        return [
            r.behavior_spec_id
            for r in self.matrix.rows
            if not r.eval_test_case_ids
        ]

    def is_gap_free(self) -> bool:
        return (
            not self.spec_elements_without_tickets()
            and not self.eval_cases_without_nodes()
            and not self.spec_elements_without_eval()
        )

    def blocking_gaps(self) -> list[str]:
        gaps: list[str] = []
        for spec_id in self.spec_elements_without_tickets():
            gaps.append(f"MISSING TICKET: {spec_id} has no engineering ticket")
        for spec_id in self.spec_elements_without_eval():
            gaps.append(f"MISSING EVAL: {spec_id} has no eval test case")
        for ec_id in self.eval_cases_without_nodes():
            gaps.append(f"UNTRACED EVAL: {ec_id} not linked to any spec element")
        return gaps
